code.imports:
import { tags } from 'decantr/tags';
import { css } from 'decantr/css';
import { Card, Statistic, icon } from 'decantr/components';

code.example:
function StatCard({ title, stats }) {
  const { div, h3 } = tags;

  return Card({},
    Card.Header({},
      h3({ class: css('_heading5') }, icon('heart-pulse'), ` ${title}`)
    ),
    Card.Body({ class: css('_grid _gc2 _gap3') },
      ...stats.map(s =>
        Statistic({ label: s.label, value: s.value, suffix: s.unit })
      )
    )
  );
}

